create schema if not exists plantaopro;
select * from (values ('CONS_PART_DEMO','Consulta particular demo','CONSULTA',250.00,0.00,0.00,'ATIVA','A'),('CONS_CONV_DEMO','Consulta convênio demo','CONSULTA',180.00,5.00,0.00,'ATIVA','A'),('PLANTAO_DEMO','Plantão realizado demo','PLANTAO',1200.00,0.00,0.00,'ATIVA','A')) as v(codigo,nome,tipo_faturamento,valor_base,percentual_desconto,percentual_acrescimo,status,reg_status) where not exists (select 1 from plantaopro.v115_regras_faturamento r where r.codigo=v.codigo);
